import type { Question } from "../types";

type Draft = Omit<Question, "rubric" | "hints" | "commonMistakes" | "explanation"> & Partial<Pick<Question, "rubric" | "hints" | "commonMistakes" | "explanation">>;
const q = (draft: Draft): Question => ({
  rubric: ["chemische begrippen juist", "redenering of berekening volledig", "eenheden en conclusie vermeld"],
  hints: ["Maak eerst een mini-plan: gegevens → chemische relatie → antwoord."],
  commonMistakes: ["Een getal of begrip noemen zonder uit te leggen waarom het past."],
  explanation: "Vergelijk je antwoord met het model: een toetsantwoord toont zowel de stap als de reden.",
  ...draft,
});

// Deze records vervangen gelijknamige, kortere instapvragen in de actieve bank.
export const qualityReplacementQuestions: Question[] = [
  q({ id: "m10-01", module: "M10", topic: "equivalentiepunt", skill: "toetsbegrip", level: 1, type: "open", question: "Bij een titratie van azijnzuur met natronloog verandert de indicator van kleur. Leg uit wat het equivalentiepunt precies betekent en waarom de kleurverandering alleen een praktische aanwijzing is.", modelAnswer: "Bij het equivalentiepunt hebben CH₃COOH en OH⁻ precies volgens de reactieverhouding gereageerd; voor azijnzuur en OH⁻ is dat 1 : 1. De indicator verandert in een omslaggebied rond dat punt. Het zichtbare eindpunt benadert dus het berekende equivalentiepunt, maar is niet de definitie ervan." }),
  q({ id: "m10-02", module: "M10", topic: "buret", skill: "aflezen", level: 1, type: "calculation", question: "Gebruik de meniscusfiguur. De onderkant van de meniscus staat eerst op 0,84 mL en na de titratie op 18,36 mL. Bereken het gebruikte volume natronloog in mL én L.", correctAnswer: "17,52 mL = 0,01752 L", modelAnswer: "Eindantwoord: 17,52 mL = 0,01752 L. Verbruik = eindstand − beginstand = 18,36 − 0,84 = 17,52 mL. Voor n = molariteit × V: 17,52 mL = 0,01752 L.", steps: ["Lees onderkant meniscus op ooghoogte.", "Eindstand min beginstand.", "Deel mL door 1000 voor L."], visual: { type: "diagram", component: "TitrationSetupDiagram", variant: "meniscus", alt: "Buret met meniscus voor aflezen", caption: "Lees de onderkant van de meniscus; gebruik daarna eindstand min beginstand.", purpose: "read-data" } }),
  q({ id: "m10-03", module: "M10", topic: "Schellbachstreep", skill: "praktijk uitleggen", level: 1, type: "open", question: "Leg uit hoe een Schellbachstreep helpt bij het aflezen van een buret en welke fout je voorkomt door op ooghoogte te kijken.", modelAnswer: "De donkere lijnen van de Schellbachstreep vormen bij de meniscus een scherpe punt. Dat maakt de onderkant beter zichtbaar. Op ooghoogte voorkom je parallax: een te hoge of te lage kijkhoek geeft een systematisch verkeerde stand." }),
  q({ id: "m10-04", module: "M10", topic: "n = molariteit × volume", skill: "berekenen", level: 1, type: "calculation", question: "Tijdens een titratie is 18,40 mL 0,1000 mol/L NaOH verbruikt. Bereken hoeveel mol natronloog heeft gereageerd.", correctAnswer: "1,840 × 10⁻³ mol", modelAnswer: "V = 0,01840 L. n(NaOH) = molariteit × V = 0,1000 × 0,01840 = 1,840 × 10⁻³ mol.", steps: ["Zet mL om naar L.", "Schrijf n = molariteit × V.", "Vul in met mol/L en L.", "Noteer mol als eenheid."] }),
  q({ id: "m10-05", module: "M10", topic: "molverhouding", skill: "berekenen", level: 2, type: "calculation", question: "20,00 mL azijn vraagt 16,50 mL 0,2000 mol/L NaOH. Bereken de molariteit van azijnzuur. Gebruik CH₃COOH + OH⁻ → CH₃COO⁻ + H₂O.", correctAnswer: "0,1650 mol/L", modelAnswer: "Eindantwoord: 0,1650 mol/L. n(NaOH) = 0,2000 × 0,01650 = 3,300 × 10⁻³ mol. De verhouding CH₃COOH : OH⁻ is 1 : 1, dus evenveel mol azijnzuur. molariteit = 3,300 × 10⁻³ / 0,02000 = 0,1650 mol/L. Chemisch klopt dit omdat OH⁻ één proton van CH₃COOH opneemt.", steps: ["Zet titrantvolume om naar L.", "Bereken mol NaOH.", "Gebruik de 1 : 1-verhouding.", "Deel door 0,02000 L monster."] }),
  q({ id: "m10-06", module: "M10", topic: "massa-aandeel", skill: "berekenen", level: 2, type: "calculation", question: "Een azijnmonster van 25,30 g bevat volgens de titratie 2,000 × 10⁻² mol CH₃COOH. Bereken hoeveel procent van de massa van het monster uit azijnzuur bestaat. molmassa = 60,05 g/mol.", correctAnswer: "4,75%", modelAnswer: "m(azijnzuur) = 2,000 × 10⁻² × 60,05 = 1,201 g. Massapercentage = 1,201 / 25,30 × 100% = 4,75%.", steps: ["Zet mol om naar massa met molmassa.", "Deel door massa van het monster.", "Vermenigvuldig met 100%."], commonMistakes: ["Mol rechtstreeks door de monstermassa delen.", "Molmassa vergeten."] }),
  q({ id: "m10-07", module: "M10", topic: "gemiddelde titraties", skill: "data beoordelen", level: 2, type: "open", question: "Drie concordante titraties geven 18,22 mL, 18,24 mL en 18,25 mL. Een vierde geeft 18,66 mL. Welke waarden gebruik je voor een voorlopig gemiddelde en welke vervolgstap is zorgvuldig?", modelAnswer: "18,66 mL is een mogelijke uitschieter, omdat hij veel verder ligt dan de drie waarden rond 18,2 mL. Gemiddeld voorlopig de concordante waarden: 18,24 mL. Onderzoek de oorzaak en herhaal de meting voordat je de uitschieter definitief weglaat." }),
  q({ id: "m10-08", module: "M10", topic: "spoelen", skill: "foutenanalyse", level: 2, type: "open", question: "Een buret is na spoelen nog gevuld met demiwater en wordt daarna met NaOH gevuld. Wordt de berekende molariteit van azijnzuur te hoog of te laag? Leg uit.", modelAnswer: "Te hoog. Restwater verdunt de NaOH in de buret. Daardoor is meer buretvolume nodig om hetzelfde aantal mol zuur te neutraliseren. Als je daarna ten onrechte met de oorspronkelijke, hogere NaOH-molariteit rekent, bereken je te veel mol NaOH en dus te veel azijnzuur.", commonMistakes: ["Alleen 'verdunnen' schrijven zonder gevolg voor n = c × V."] }),
  q({ id: "m10-09", module: "M10", topic: "spoelen", skill: "foutenanalyse", level: 2, type: "open", question: "Een erlenmeyer is na spoelen nog nat met demiwater, maar bevat een nauwkeurig gepipetteerd azijnmonster. Verandert de berekende molariteit meestal? Leg uit.", modelAnswer: "Nee. Het demiwater verdunt de inhoud van de erlenmeyer, maar verandert niet het aantal mol azijnzuur dat met de pipet is ingebracht. Voor neutralisatie is dus dezelfde hoeveelheid NaOH nodig, zolang je het eindpunt goed bepaalt." }),
  q({ id: "m10-10", module: "M10", topic: "eindpunt", skill: "foutenanalyse", level: 3, type: "open", question: "Een leerling titreert na de eerste blijvende roze tint nog 0,30 mL NaOH door. Wordt de berekende molariteit van azijnzuur te hoog of te laag? Leg uit met n = molariteit × V.", modelAnswer: "Te hoog. Het afgelezen V(NaOH) is te groot. Met n = molariteit × V bereken je daardoor te veel mol NaOH en via de 1 : 1-verhouding te veel mol azijnzuur." }),
  q({ id: "m10-11", module: "M10", topic: "luchtbel", skill: "foutenanalyse", level: 3, type: "open", question: "Bij het begin van een titratie zit een luchtbel onder de kraan van de buret. Tijdens de titratie verdwijnt die bel. Wordt het afgelezen verbruik groter of kleiner dan het werkelijk in de erlenmeyer gekomen volume? Wat gebeurt er met de uitkomst?", modelAnswer: "Het afgelezen verbruik is groter: een deel van de buretinhoud vult eerst de ruimte van de luchtbel en komt niet in de erlenmeyer. Reken je toch met het afgelezen volume, dan bereken je te veel mol titrant en dus een te hoge hoeveelheid/concentratie van het monster." }),
  q({ id: "m10-12", module: "M10", topic: "indicator", skill: "BINAS toepassen", level: 3, type: "open", question: "Je titreert een zwak zuur met een sterke base. Leg met BINAS tabel 52A uit welk omslaggebied je zoekt voor een indicator en waarom een indicator voor een sterk zuur/sterke base niet automatisch past.", modelAnswer: "Zoek een indicator waarvan het omslagtraject rond de pH van het equivalentiepunt ligt. Bij zwak zuur/sterke base ligt dat equivalentiepunt boven pH 7. Een indicator met omslag rond pH 7 kan daarom te vroeg of te laat verkleuren." }),
  q({ id: "m10-13", module: "M10", topic: "pH", skill: "berekenen", level: 2, type: "calculation", question: "Bereken de pH van 2,50 × 10⁻³ mol/L HCl. Ga uit van volledige dissociatie.", correctAnswer: "2,60", modelAnswer: "[H₃O⁺] = 2,50 × 10⁻³ mol/L. pH = −log(2,50 × 10⁻³) = 2,60.", steps: ["Neem [H₃O⁺] gelijk aan de HCl-molariteit.", "Gebruik pH = −log[H₃O⁺].", "Rond passend af."] }),
  q({ id: "m10-14", module: "M10", topic: "zuur-base-reacties", skill: "protonoverdracht", level: 2, type: "open", question: "Leg in CH₃COOH + OH⁻ → CH₃COO⁻ + H₂O uit welke deeltjes zuur en base zijn. Gebruik protondonor en protonacceptor.", modelAnswer: "CH₃COOH staat een proton af en is de protondonor, dus het zuur. OH⁻ neemt dat proton op en is de protonacceptor, dus de base. De producten zijn het geconjugeerde base-deeltje CH₃COO⁻ en water." }),
  q({ id: "m10-15", module: "M10", topic: "verdunnen en titreren", skill: "rekenketen", level: 3, type: "calculation", question: "5,00 mL natuurazijn wordt verdund tot 100,0 mL. Van de verdunde oplossing vraagt 25,00 mL precies 20,80 mL 0,1000 mol/L NaOH. Bereken de molariteit van azijnzuur in de oorspronkelijke azijn.", correctAnswer: "1,664 mol/L", modelAnswer: "n(NaOH) = 0,1000 × 0,02080 = 2,080 × 10⁻³ mol. Dit is 1 : 1 de hoeveelheid zuur in 25,00 mL verdunde oplossing. molariteit verdund = 0,08320 mol/L. De verdunningsfactor is 100,0 / 5,00 = 20,0, dus oorspronkelijk 1,664 mol/L.", steps: ["Bereken mol NaOH uit titratievolume.", "Gebruik de 1 : 1-verhouding.", "Bereken molariteit verdunde oplossing.", "Vermenigvuldig met verdunningsfactor 20,0."] }),
  q({ id: "m10-16", module: "M10", topic: "meervoudige protonen", skill: "molverhouding", level: 3, type: "calculation", question: "15,00 mL H₂SO₄ vraagt 24,00 mL 0,1500 mol/L NaOH. Bereken de molariteit van H₂SO₄.", correctAnswer: "0,1200 mol/L", modelAnswer: "n(OH⁻) = 0,1500 × 0,02400 = 3,600 × 10⁻³ mol. H₂SO₄ : OH⁻ = 1 : 2, dus n(H₂SO₄) = 1,800 × 10⁻³ mol. molariteit = 1,800 × 10⁻³ / 0,01500 = 0,1200 mol/L.", steps: ["Zet 24,00 mL om naar L.", "Bereken mol OH⁻.", "Deel door 2 voor H₂SO₄.", "Deel door monstervolume in L."] }),
  q({ id: "m10-17", module: "M10", topic: "massa-aandeel", skill: "rekenketen", level: 4, type: "calculation", question: "8,00 mL citroensap met dichtheid 1,03 g/mL wordt verdund tot 100,0 mL. Een aliquot van 20,00 mL verbruikt 18,75 mL 0,08000 mol/L NaOH. Neem citroenzuur als H₃Cit. Bereken het massapercentage citroenzuur; molmassa H₃Cit = 192,12 g/mol.", correctAnswer: "5,83%", modelAnswer: "n(OH⁻) aliquot = 0,08000 × 0,01875 = 1,500 × 10⁻³ mol. n(zuur) aliquot = /3 = 5,000 × 10⁻⁴ mol. Hele oplossing bevat vijfmaal zoveel: 2,500 × 10⁻³ mol. m zuur = 0,4803 g; massa sap = 8,00 × 1,03 = 8,24 g. Massa% = 0,4803/8,24 × 100% = 5,83%.", steps: ["Bereken mol OH⁻.", "Gebruik de 3 : 1-verhouding.", "Schaal op van aliquot naar hele oplossing.", "Zet mol zuur om naar massa en deel door monstermassa."] }),
  q({ id: "m10-18", module: "M10", topic: "evenwicht", skill: "K interpreteren", level: 3, type: "open", question: "Voor een reactie is K veel groter dan 1. Wat zegt dit over de samenstelling bij evenwicht, en wat zegt het juist niet over de reactiesnelheid?", modelAnswer: "Bij evenwicht zijn producten relatief bevoordeeld ten opzichte van beginstoffen. K zegt echter niets rechtstreeks over hoe snel dat evenwicht bereikt wordt; een reactie kan thermodynamisch gunstig maar kinetisch langzaam zijn." }),
  q({ id: "m10-19", module: "M10", topic: "duurzaamheid", skill: "beoordelen", level: 4, type: "open", question: "Beoordeel de uitspraak: 'Een biobrandstof is altijd duurzaam, want bij verbranding ontstaat alleen eerder opgenomen CO₂.' Noem twee voorwaarden voor een volledig oordeel.", modelAnswer: "De uitspraak is te simpel. Je moet bijvoorbeeld kijken naar landgebruik/ontbossing, energie voor teelt en verwerking, transport, concurrentie met voedsel en andere emissies. Alleen de koolstofkringloop van verbranding is onvoldoende voor een duurzaamheidsbeoordeling." }),
  q({ id: "m10-20", module: "M10", topic: "om-estering", skill: "structuurreactie", level: 4, type: "open", question: "Leg uit wat om-estering inhoudt bij een triglyceride en waarom de esterbindingen daarbij chemisch centraal staan.", modelAnswer: "Bij om-estering worden esterbindingen van een triglyceride omgewisseld met een alcohol, vaak methanol. Er ontstaan dan andere esters, bijvoorbeeld biodiesel, en glycerol. De reactie verandert dus welke alcoholrest aan de carbonzuurrest gekoppeld is." }),

  q({ id: "priority-m8-03", module: "M8", topic: "M+2", skill: "chloor herkennen", level: 3, type: "open", question: "Gebruik het oefenmassaspectrum. Een component in GC-MS heeft M en M+2 in verhouding ongeveer 3 : 1. Welke isotoopcombinatie past hierbij en welke BINAS-tabel ondersteunt dit?", modelAnswer: "Eindantwoord: één chlooratoom past bij een M : M+2-verhouding van ongeveer 3 : 1. ³⁵Cl is veel algemener dan ³⁷Cl, dat twee u zwaarder is. Gebruik BINAS tabel 39D als controle van isotopenpatronen; de conclusie blijft een aanwijzing voor Cl, geen volledige structuur.", visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "chlorine", alt: "Oefenmassaspectrum met M en M plus 2 patroon van chloor", caption: "Een herkenbaar patroon naast M kan een element aanwijzen.", purpose: "interpret-spectrum" } }),
  q({ id: "priority-m8-04", module: "M8", topic: "M+2", skill: "broom herkennen", level: 3, type: "open", question: "Gebruik het oefenmassaspectrum. Een component heeft M en M+2 met bijna dezelfde hoogte. Welke conclusie over halogenen is sterk en welke conclusie over de volledige structuur is nog te vergaand?", modelAnswer: "Eindantwoord: één Br-atoom is een sterke aanwijzing; de exacte structuur of naam is nog niet bewezen. ⁷⁹Br en ⁸¹Br komen ongeveer even vaak voor en verschillen 2 u, waardoor M en M+2 ongeveer even hoog kunnen zijn. Voor de volledige structuur zijn ook fragmenten, IR of NMR nodig.", visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "bromine", alt: "Oefenmassaspectrum met M en M plus 2 patroon van broom", caption: "Gelijke M- en M+2-pieken zijn een broomaanwijzing.", purpose: "interpret-spectrum" } }),
  q({ id: "priority-m8-05", module: "M8", topic: "isotopen", skill: "gemiddelde massa", level: 2, type: "calculation", question: "Een element bestaat uit 75,0% X-35 en 25,0% X-37. Bereken de gemiddelde atoommassa.", correctAnswer: "35,5 u", modelAnswer: "0,750 × 35 + 0,250 × 37 = 35,50 u, dus 35,5 u.", steps: ["Zet percentages om naar breuken.", "Vermenigvuldig elke fractie met het massagetal.", "Tel beide bijdragen op."] }),
  q({ id: "priority-m8-06", module: "M8", topic: "massaspectrometer", skill: "instrument uitleggen", level: 2, type: "order", question: "Zet de kernstappen in een massaspectrometer in de juiste volgorde: detecteren, verdampen, ioniseren, versnellen, scheiden op m/z.", options: ["detecteren", "verdampen", "ioniseren", "versnellen", "scheiden op m/z"], correctAnswer: "verdampen > ioniseren > versnellen > scheiden op m/z > detecteren", modelAnswer: "Moleculen moeten eerst gasvormig en geladen zijn. Daarna kunnen velden ionen versnellen en scheiden; de detector maakt daar pieken van.", steps: ["Maak gasvormig.", "Maak geladen.", "Versnel en scheid.", "Registreer de ionen."] }),
  q({ id: "priority-m8-07", module: "M8", topic: "fragmentatie", skill: "verklaren", level: 2, type: "open", question: "Gebruik het oefenmassaspectrum. Waarom kan een fragmention bij m/z 43 de hoogste piek zijn terwijl de M-piek bij m/z 86 ligt?", modelAnswer: "Eindantwoord: m/z 43 kan de basispiek zijn omdat een stabiel fragmention vaak ontstaat; de M-piek bij m/z 86 blijft het hele molecuulion. De detector registreert dan veel ionen bij m/z 43. Piekhoogte verandert de betekenis van M niet.", visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "carbon", alt: "Oefenmassaspectrum met fragment bij 43 en M bij 86", caption: "De basispiek is vaak een fragment, niet het hele molecuul.", purpose: "interpret-spectrum" } }),
  q({ id: "priority-m8-09", module: "M8", topic: "GC-MS", skill: "technieken combineren", level: 3, type: "open", question: "Gebruik het GC-MS-schema. Waarom is een massaspectrum van één GC-piek overtuigender voor identificatie dan één spectrum van een ongescheiden mengsel?", modelAnswer: "Eindantwoord: het spectrum van één GC-piek is overtuigender omdat het vooral bij één gescheiden component hoort. GC scheidt componenten eerst in de tijd. In een ongescheiden mengsel kunnen molecuulionen en fragmenten van verschillende stoffen door elkaar lopen, waardoor identificatie zwakker wordt.", visual: { type: "diagram", component: "GcMsDiagram", alt: "GC gevolgd door massaspectrometer", caption: "Eerst scheiden, dan per piek identificeren.", purpose: "explanation-only" } }),
  q({ id: "priority-m8-11", module: "M8", topic: "NMR", skill: "structuurinformatie", level: 2, type: "open", question: "Welke informatie kan ¹H-NMR geven naast een molecuulmassa uit MS, en waarom helpt dat bij structuuronderscheid?", modelAnswer: "¹H-NMR laat verschillende waterstofomgevingen zien en kan via splitsing iets over naburige H-atomen vertellen. Isomeren met dezelfde molmassa kunnen daardoor toch worden onderscheiden.", rubric: ["H-omgevingen", "buren/splitsing of structuur", "zelfde massa is niet dezelfde structuur"] }),
  q({ id: "priority-m8-12", module: "M8", topic: "atoommodel", skill: "micro-macro", level: 3, type: "open", question: "Een goudfolie-experiment laat zien dat de meeste alfadeeltjes rechtdoor gaan en enkele sterk afbuigen. Leg beide waarnemingen uit met Rutherfords model.", modelAnswer: "De meeste gaan rechtdoor omdat een atoom grotendeels lege ruimte is. De enkele sterke afbuigingen ontstaan dicht bij een kleine, dichte, positief geladen kern met veel massa.", rubric: ["lege ruimte", "kleine positieve kern", "beide waarnemingen gekoppeld"] }),
  q({ id: "priority-m8-13", module: "M8", topic: "BINAS 39D", skill: "spectrum interpreteren", level: 3, type: "open", question: "Je ziet een M+2-patroon en twijfelt tussen Cl en Br. Leg uit hoe BINAS 39D je helpt en welke extra spectruminformatie je daarna nog controleert.", modelAnswer: "Vergelijk de verwachte natuurlijke isotopenverhoudingen in tabel 39D met de relatieve piekhoogten. Controleer daarna of het patroon echt naast de M-piek ligt en bekijk fragmentpieken en eventuele andere technieken voordat je een structuur noemt." }),
  q({ id: "priority-m8-15", module: "M8", topic: "analysetechnieken", skill: "strategie", level: 4, type: "open", question: "Ontwerp een korte analysevolgorde voor een onbekend vluchtig organisch mengsel met GC-MS, IR en NMR. Benoem wat elke techniek toevoegt.", modelAnswer: "Gebruik GC om componenten te scheiden en MS voor massa, isotopen en fragmenten per piek. Gebruik IR voor functionele groepen en NMR voor verschillende H- of C-omgevingen. Samen geven deze technieken veel sterker structuurbewijs dan één techniek." }),

  q({ id: "priority-m5d-01", module: "M5D", topic: "peptidebinding", skill: "structuur herkennen", level: 2, type: "open", question: "Gebruik het peptide-schema. Wijs in het fragment H₂N–CH(R)–C(=O)–NH–CH(R')–COOH de peptidebinding aan en leg uit waarom dit een amidebinding is.", modelAnswer: "Eindantwoord: de peptidebinding is –C(=O)–NH–. Zij verbindt de carboxylgroep van het ene aminozuur met de aminogroep van het volgende; dat patroon heet een amidebinding.", visual: { type: "diagram", component: "PeptideBondFormationDiagram", variant: "peptideBondHighlight", alt: "Dipeptide met gemarkeerde peptidebinding C(=O)-NH.", caption: "Zoek altijd de combinatie C(=O) direct naast N.", purpose: "interpret-structure" } }),
  q({ id: "priority-m5d-02", module: "M5D", topic: "aminozuren", skill: "functionele groepen", level: 2, type: "open", question: "Leg uit waaraan je in H₂N–CH(R)–COOH herkent dat dit een aminozuur is, en welk deel per aminozuur verschilt.", modelAnswer: "Het molecuul heeft zowel een aminogroep H₂N– als een carboxylgroep –COOH aan dezelfde centrale C. De R-groep verschilt tussen aminozuren en beïnvloedt hun eigenschappen.", rubric: ["aminogroep", "carboxylgroep", "R-groep verschilt"] }),
  q({ id: "priority-m5d-03", module: "M5D", topic: "hydrolyse", skill: "reactie verklaren", level: 3, type: "open", question: "Gebruik het hydrolyseschema. Leg uit hoe hydrolyse van een dipeptide twee aminozuren kan vormen. Noem wat water doet met de peptidebinding.", modelAnswer: "Eindantwoord: water reageert met de peptidebinding –C(=O)–NH–. Een OH-deel eindigt bij de carboxylzijde en een H-deel bij de aminokant, waardoor de koppeling breekt en twee aminozuren ontstaan.", visual: { type: "diagram", component: "PeptideBondFormationDiagram", variant: "hydrolysis", alt: "Hydrolyse van een peptidebinding met water als reactant.", caption: "Water helpt de peptidebinding open te breken.", purpose: "explanation-only" } }),
  q({ id: "priority-m5d-04", module: "M5D", topic: "DNA als polymeer", skill: "toetsuitleg", level: 3, type: "open", question: "Gebruik het DNA-schema. Leg uit waarom DNA tegelijk een polymeer én een informatiedrager is. Gebruik nucleotide, fosfaat-suiker-ruggengraat en basevolgorde.", modelAnswer: "Eindantwoord: DNA is een polymeer omdat het een lange keten van herhaalde nucleotiden is, en een informatiedrager omdat de basevolgorde variabel is. Fosfaat en suiker vormen de covalente ruggengraat; de volgorde van de basen draagt de genetische informatie.", visual: { type: "diagram", component: "DnaPolymerDiagram", alt: "DNA-polymeer met ruggengraat en basen", caption: "De ruggengraat geeft structuur; de basenvolgorde geeft informatie.", purpose: "explanation-only" } }),
  q({ id: "priority-m5d-05", module: "M5D", topic: "nucleotide", skill: "bouwsteen herkennen", level: 1, type: "open", question: "Gebruik het nucleotide-schema. Een tekening bevat fosfaat, desoxyribose en cytosine. Leg uit waarom dit één DNA-nucleotide is en niet drie losse moleculen.", modelAnswer: "Eindantwoord: fosfaat, suiker en één base vormen samen één nucleotide wanneer ze covalent gekoppeld zijn. In DNA zijn die onderdelen tot één bouwsteen verbonden; een losse base is nog geen nucleotide.", visual: { type: "diagram", component: "NucleotideDiagram", alt: "Nucleotide met fosfaat suiker en base", caption: "Een nucleotide bestaat altijd uit drie gekoppelde delen.", purpose: "interpret-structure" } }),
  q({ id: "priority-m5d-06", module: "M5D", topic: "transcriptie", skill: "toepassen", level: 3, type: "calculation", question: "Gebruik het transcriptieschema. De DNA-matrijsstreng is 3′–TAC GGA AAA–5′. Schrijf het mRNA dat bij transcriptie ontstaat in 5′→3′-richting.", correctAnswer: "5′–AUG CCU UUU–3′", modelAnswer: "Eindantwoord: mRNA vormt complementair aan de matrijs: T→A, A→U, C→G en G→C. Dat geeft 5′–AUG CCU UUU–3′.", steps: ["Lees de matrijs 3′→5′.", "Gebruik RNA-basen, dus U in plaats van T.", "Noteer mRNA 5′→3′."], visual: { type: "diagram", component: "DnaExpressionDiagram", variant: "transcription", alt: "Schema van transcriptie van DNA naar mRNA.", caption: "Gebruik RNA-regels: A-U, T-A, C-G en G-C.", purpose: "calculation-support" } }),
  q({ id: "priority-m5d-07", module: "M5D", topic: "translatie", skill: "codons", level: 3, type: "open", question: "Gebruik een codontabel voor mRNA 5′–AUG CCU UUU–3′. Leg uit hoe je de aminozuurvolgorde bepaalt.", modelAnswer: "Lees het mRNA in triplets: AUG, CCU en UUU. Zoek elk codon in de codontabel op; dat levert methionine, proline en fenylalanine. Transcriptie maakt mRNA, translatie leest de codons." }),
  q({ id: "priority-m5d-08", module: "M5D", topic: "primaire structuur", skill: "eiwitstructuur", level: 2, type: "open", question: "Wat is de primaire structuur van een eiwit en waarom kan een verandering daarin later ook de tertiaire structuur veranderen?", modelAnswer: "De primaire structuur is de volgorde van aminozuren in de peptideketen. Andere R-groepen op andere plaatsen kunnen andere aantrekking, afstoting en vouwing geven, waardoor de uiteindelijke ruimtelijke vorm verandert." }),
  q({ id: "priority-m5d-09", module: "M5D", topic: "secundaire en tertiaire structuur", skill: "vergelijken", level: 3, type: "open", question: "Vergelijk secundaire en tertiaire eiwitstructuur en noem welke interacties de vorm kunnen stabiliseren.", modelAnswer: "Secundaire structuur is lokale regelmatige vouwing, zoals een helix of plaat, vaak door waterstofbruggen in de ruggengraat. Tertiaire structuur is de volledige 3D-vorm van één keten, gestabiliseerd door onder meer H-bruggen, ionbindingen, hydrofobe interacties en soms zwavelbruggen." }),
  q({ id: "priority-m5d-10", module: "M5D", topic: "denaturatie", skill: "pH-effect", level: 3, type: "open", question: "Gebruik het denaturatieschema. Een enzym verliest bij lage pH zijn werking, terwijl peptidebindingen intact blijven. Leg uit hoe dat kan.", modelAnswer: "Eindantwoord: lage pH verandert ladingen van R-groepen. Daardoor kunnen ionbindingen en waterstofbruggen die de 3D-vorm stabiliseren veranderen. De actieve plaats verandert, ook als de covalente peptideketen nog heel is.", visual: { type: "diagram", component: "ProteinStructureDiagram", variant: "denaturation", alt: "Werkend en gedenatureerd enzym naast elkaar.", caption: "De peptideketen kan intact blijven terwijl de actieve plaats vervormt.", purpose: "explanation-only" } }),
  q({ id: "priority-m5d-11", module: "M5D", topic: "enzymen", skill: "temperatuur-effect", level: 3, type: "open", question: "Leg uit waarom verwarmen een enzym eerst sneller kan laten werken maar bij te hoge temperatuur de werking laat afnemen.", modelAnswer: "Bij opwarming bewegen deeltjes sneller en zijn effectieve botsingen vaker mogelijk. Boven een optimum kan de eiwitvorm denatureren; dan past het substraat niet meer goed in de actieve plaats en daalt de activiteit." }),
  q({ id: "priority-m5d-12", module: "M5D", topic: "condensatiepolymeren", skill: "polymerisatie", level: 3, type: "open", question: "Een dizuur reageert met een diol. Leg uit waarom een polyester ontstaat, welke binding gevormd wordt en welk klein molecuul vrijkomt.", modelAnswer: "–COOH van het dizuur reageert met –OH van de diol. Er ontstaat steeds een esterbinding –C(=O)–O– en water. Omdat beide monomeren twee reagerende groepen hebben, kan een lange polyesterketen groeien." }),
  q({ id: "priority-m5d-13", module: "M5D", topic: "additiepolymeren", skill: "polymerisatie", level: 3, type: "open", question: "Leg op moleculair niveau uit waarom etheen additiepolymerisatie ondergaat en waarom daarbij geen water ontstaat.", modelAnswer: "De C=C-dubbele binding van etheen opent. Nieuwe C–C-enkelbindingen koppelen vele monomeren in een keten. Er verlaten geen atomen de monomeren, dus er ontstaat geen klein bijproduct zoals water." }),
  q({ id: "priority-m5d-14", module: "M5D", topic: "polyamide", skill: "materiaalredeneren", level: 4, type: "open", question: "Vergelijk een polyamide met polyetheen op functionele groepen en verwachte interactie met water.", modelAnswer: "Een polyamide bevat polaire amidegroepen met C=O en vaak N–H; die kunnen dipoolinteracties en waterstofbruggen met water vormen. Polyetheen heeft vooral apolaire C–C- en C–H-bindingen en is daarom veel hydrofober." }),
  q({ id: "priority-m5d-15", module: "M5D", topic: "DNA en enzymen", skill: "combineren", level: 4, type: "open", question: "Gebruik het schema. Leg de keten DNA → mRNA → aminozuurvolgorde → enzymvorm → enzymwerking in vijf korte, causale stappen uit.", modelAnswer: "Eindantwoord: de DNA-basevolgorde wordt bij transcriptie gekopieerd naar mRNA. Codons in mRNA worden bij translatie gekoppeld aan aminozuren. De aminozuurvolgorde vormt de primaire eiwitstructuur. Die vouwt tot een 3D-vorm met een actieve plaats. Daardoor bepaalt de DNA-informatie indirect welke enzymreactie goed verloopt.", visual: { type: "diagram", component: "DnaExpressionDiagram", variant: "dnaToProteinSteps", alt: "Route van DNA naar mRNA, codons en eiwitketen.", caption: "Volg de route stap voor stap van code naar enzymwerking.", purpose: "explanation-only" } }),
  q({ id: "priority-m10-01", module: "M10", topic: "buret", skill: "aflezen", level: 1, type: "calculation", question: "Gebruik de meetfiguur. De beginstand van de buret is 1,25 mL en de eindstand is 19,70 mL. Bereken het gebruikte volume in mL én in L.", correctAnswer: "18,45 mL = 0,01845 L", modelAnswer: "Eindantwoord: 18,45 mL = 0,01845 L. Gegevens: beginstand 1,25 mL en eindstand 19,70 mL. Verbruik = eindstand − beginstand = 19,70 − 1,25 = 18,45 mL. Voor n = molariteit × volume moet het volume in liter: 18,45 mL / 1000 = 0,01845 L. Chemisch klopt dit omdat de buretstand aangeeft hoeveel titrant uit de buret is gelopen.", steps: ["Lees begin- en eindstand uit de meetfiguur.", "Bereken eindstand − beginstand.", "Zet mL om naar L.", "Noteer beide eenheden."], rubric: ["18,45 mL", "0,01845 L", "eindstand − beginstand gebruikt"], visual: { type: "diagram", component: "QuestionTitrationDataFigure", variant: "buret-readings", alt: "Meetfiguur met beginstand en eindstand van een buret", caption: "Lees de twee standen en bereken het verschil.", purpose: "read-data" } }),
  q({ id: "priority-m10-04", module: "M10", topic: "n = c × V", skill: "eenheden", level: 1, type: "open", question: "Een leerling vult in n = molariteit × volume het buretvolume 18,45 in, zonder mL naar L om te zetten. Wordt n te hoog of te laag berekend, en met welke factor?", modelAnswer: "Eindantwoord: n wordt 1000 keer te hoog. De molariteit staat in mol/L, dus het volume moet in liter. De juiste invoer is 18,45 mL = 0,01845 L. Wie 18,45 invult, gebruikt een volume dat 1000 keer te groot is. Daarom wordt ook het berekende aantal mol 1000 keer te groot.", rubric: ["te hoog", "factor 1000", "mol/L gekoppeld aan liter"], hints: ["Kijk naar de L in mol/L.", "Vergelijk 18,45 mL met 0,01845 L.", "De fout in volume werkt rechtstreeks door in n."], commonMistakes: ["Alleen 'te hoog' noemen zonder factor.", "Vergeten dat molariteit per liter is."] }),
  q({ id: "priority-m10-05", module: "M10", topic: "titratie", skill: "stappenplan", level: 2, type: "order", question: "Gebruik de rekenflow. Zet deze titratiestappen in de juiste rekenvolgorde.", options: ["Bereken de gevraagde molariteit of massa%.", "Zet het gebruikte buretvolume om naar L.", "Bereken mol titrant met n = molariteit × volume.", "Gebruik de molverhouding uit de reactievergelijking."], correctAnswer: "Zet het gebruikte buretvolume om naar L. > Bereken mol titrant met n = molariteit × volume. > Gebruik de molverhouding uit de reactievergelijking. > Bereken de gevraagde molariteit of massa%.", modelAnswer: "Eindantwoord: volume in L → mol titrant → molverhouding → gevraagde molariteit of massa%. Eerst moet het buretvolume in liter, omdat molariteit in mol/L staat. Daarna geeft n = molariteit × volume het aantal mol titrant. De reactievergelijking koppelt dat aan het monster. Pas daarna bereken je de gevraagde eindgrootheid.", steps: ["V in L", "n = molariteit × V", "molverhouding", "c of massa%"], visual: { type: "diagram", component: "QuestionTitrationDataFigure", variant: "flow", alt: "Titratie rekenflow van volume naar eindantwoord", caption: "De figuur ondersteunt de rekenvolgorde zonder het antwoord weg te geven.", purpose: "calculation-support" } }),
  q({ id: "priority-m10-06", module: "M10", topic: "titratie", skill: "berekenen", level: 2, type: "calculation", question: "25,00 mL azijnzuur wordt getitreerd met 18,60 mL 0,1000 mol/L NaOH. Bereken de molariteit van CH₃COOH. CH₃COOH + OH⁻ → CH₃COO⁻ + H₂O.", correctAnswer: "0,07440 mol/L", modelAnswer: "Eindantwoord: 0,07440 mol/L CH₃COOH. Gegevens: V(NaOH) = 18,60 mL = 0,01860 L, molariteit NaOH = 0,1000 mol/L en V(azijnzuur) = 0,02500 L. n(OH⁻) = 0,1000 × 0,01860 = 1,860 × 10⁻³ mol. De reactieverhouding CH₃COOH : OH⁻ is 1 : 1, dus n(CH₃COOH) = 1,860 × 10⁻³ mol. molariteit = n / V = 1,860 × 10⁻³ / 0,02500 = 0,07440 mol/L. Chemisch klopt dit omdat OH⁻ één proton van CH₃COOH opneemt.", steps: ["18,60 mL = 0,01860 L", "n(NaOH) = molariteit × volume", "Gebruik 1 : 1", "Deel door 0,02500 L monster"], hints: ["Begin met het NaOH-volume in liter.", "Controleer de 1 : 1-verhouding in de vergelijking.", "Deel pas op het eind door het monstervolume."], commonMistakes: ["18,60 als liter invullen.", "De molariteit van NaOH direct als molariteit azijnzuur nemen."] }),
  q({ id: "priority-m10-07", module: "M10", topic: "molverhouding", skill: "berekenen", level: 2, type: "calculation", question: "20,00 mL H₂SO₄ wordt geneutraliseerd door 24,00 mL 0,1500 mol/L NaOH. Bereken de molariteit van H₂SO₄. Gebruik H₂SO₄ + 2 OH⁻ → SO₄²⁻ + 2 H₂O.", correctAnswer: "0,09000 mol/L", modelAnswer: "Eindantwoord: 0,09000 mol/L H₂SO₄. Gegevens: V(NaOH) = 0,02400 L, molariteit NaOH = 0,1500 mol/L, V(H₂SO₄) = 0,02000 L. n(OH⁻) = 0,1500 × 0,02400 = 3,600 × 10⁻³ mol. Uit de vergelijking volgt H₂SO₄ : OH⁻ = 1 : 2, dus n(H₂SO₄) = 3,600 × 10⁻³ / 2 = 1,800 × 10⁻³ mol. molariteit H₂SO₄ = 1,800 × 10⁻³ / 0,02000 = 0,09000 mol/L.", steps: ["V(NaOH) naar L", "n(OH⁻) = molariteit × volume", "Deel door 2", "c = n / V(H₂SO₄)"], commonMistakes: ["De 1 : 2-molverhouding overslaan.", "H₂SO₄ behandelen alsof het één OH⁻ nodig heeft."] }),
  q({ id: "priority-m10-08", module: "M10", topic: "gemiddelde titratiewaarden", skill: "gegevens beoordelen", level: 2, type: "mixed", question: "Vier verbruiken zijn 18,42; 18,39; 18,41 en 19,10 mL. Welke waarden gebruik je voor een voorlopig gemiddelde en waarom?", modelAnswer: "Eindantwoord: gebruik voorlopig 18,42; 18,39 en 18,41 mL, met gemiddelde 18,41 mL. Deze drie waarden zijn concordant omdat ze dicht bij elkaar liggen. 19,10 mL is een duidelijke uitbijter. Chemisch en praktisch is het zorgvuldig om de oorzaak te onderzoeken en de titratie te herhalen voordat je de uitbijter definitief weglaat.", steps: ["Vergelijk de spreiding.", "Kies de concordante waarden.", "Bereken het gemiddelde.", "Benoem wat je met de uitbijter doet."], rubric: ["drie concordante waarden", "19,10 mL als uitbijter", "gemiddelde 18,41 mL", "herhalen/oorzaak onderzoeken"] }),
  q({ id: "priority-m10-09", module: "M10", topic: "foutenanalyse", skill: "redeneren", level: 3, type: "open", question: "De buret is na spoelen nog nat met demiwater. Daarna vult de leerling hem met NaOH, maar rekent met de opgegeven molariteit. Wordt de berekende molariteit van het zuur te hoog of te laag?", modelAnswer: "Eindantwoord: te hoog. Het restwater verdunt de NaOH, dus de werkelijke molariteit in de buret is lager dan de opgegeven molariteit. Daardoor is een groter volume nodig om hetzelfde aantal mol zuur te neutraliseren. De leerling rekent dat grotere volume met een te hoge molariteit om via n = molariteit × volume, dus berekent te veel mol OH⁻ en daardoor te veel mol zuur.", rubric: ["NaOH verdund", "groter verbruik", "te veel mol berekend", "zuurmolariteit te hoog"], hints: ["Vraag eerst: wat gebeurt met de werkelijke NaOH-molariteit?", "Koppel daarna aan het benodigde volume.", "Gebruik n = molariteit × volume voor de richting."] }),
  q({ id: "priority-m10-10", module: "M10", topic: "foutenanalyse", skill: "redeneren", level: 3, type: "open", question: "Een leerling leest de beginstand van de buret 0,10 mL te laag af en de eindstand correct. Wat gebeurt er met het berekende zuurgehalte?", modelAnswer: "Eindantwoord: het berekende zuurgehalte wordt te hoog. Het verbruik wordt berekend als eindstand − beginstand. Als de beginstand 0,10 mL te laag is afgelezen, wordt het verschil 0,10 mL te groot. Daardoor bereken je met n = molariteit × volume te veel mol titrant. Bij een 1 : 1-titratie betekent dat ook te veel mol zuur.", rubric: ["verbruik te groot", "n titrant te groot", "zuurgehalte te hoog"] }),
  q({ id: "priority-m10-11", module: "M10", topic: "massa%", skill: "toetsrekenen", level: 3, type: "calculation", question: "Van 25,00 mL schoonmaakazijn met massa 25,52 g is via titratie gevonden dat het monster 2,040 × 10⁻² mol CH₃COOH bevat. Bereken hoeveel procent van de massa van het monster uit CH₃COOH bestaat. molmassa = 60,05 g/mol.", correctAnswer: "4,79%", modelAnswer: "Eindantwoord: 4,79 massaprocent CH₃COOH. Gegevens: n(CH₃COOH) = 2,040 × 10⁻² mol, molmassa = 60,05 g/mol en massa monster = 25,52 g. Massa CH₃COOH = n × molmassa = 2,040 × 10⁻² × 60,05 = 1,225 g. Massa% = 1,225 / 25,52 × 100% = 4,79%. Chemisch klopt dit omdat de titratie eerst mol zuur geeft en molmassa pas daarna mol naar gram omzet.", steps: ["m = n × molmassa", "massa% = massa stof / massa monster × 100%", "Rond passend af"], commonMistakes: ["Mol direct als gram gebruiken.", "Molmassa vergeten.", "Delen door volume in plaats van massa monster."] }),
  q({ id: "priority-m10-12", module: "M10", topic: "significantie", skill: "significantie", level: 3, type: "open", question: "Een buretverbruik wordt afgelezen als 18,4 mL en de molariteit van NaOH is 0,1000 mol/L. Waarom is een eindantwoord met zes significante cijfers meestal niet verdedigbaar?", modelAnswer: "Eindantwoord: zes significante cijfers zijn niet verdedigbaar. De aflezing 18,4 mL heeft drie significante cijfers en begrenst de meetnauwkeurigheid. Een eindantwoord met zes significante cijfers zou doen alsof het volume veel nauwkeuriger is gemeten dan werkelijk. Chemisch is dat belangrijk omdat n = molariteit × volume direct van die meetwaarde afhangt.", rubric: ["18,4 mL heeft drie significante cijfers", "minst nauwkeurige gegeven begrenst", "schijnnauwkeurigheid uitgelegd"] }),
  q({ id: "priority-m10-13", module: "M10", topic: "equivalentiepunt", skill: "toetsuitleg", level: 4, type: "mixed", question: "Leg het verschil uit tussen equivalentiepunt en eindpunt bij de titratie van azijnzuur met NaOH. Betrek de keuze van fenolftaleïne.", modelAnswer: "Eindantwoord: het equivalentiepunt is het theoretische stoichiometrische punt; het eindpunt is de waargenomen kleurverandering. Bij CH₃COOH + OH⁻ is de molverhouding 1 : 1. Fenolftaleïne kies je omdat het omslaggebied in het steile pH-gebied rond het equivalentiepunt van deze zwak-zuur/sterke-base-titratie ligt. De indicator bewijst dus niet zelf de molverhouding, maar maakt een praktisch eindpunt zichtbaar.", rubric: ["theoretisch versus waargenomen", "1 : 1", "fenolftaleïne bij steile pH-zone", "indicatorrol correct"], hints: ["Noem eerst het verschil tussen rekenpunt en kleurpunt.", "Koppel fenolftaleïne aan het pH-gebied.", "Gebruik de reactieverhouding in je uitleg."] }),
  q({ id: "priority-m10-14", module: "M10", topic: "titratie", skill: "8+ rekenketen", level: 4, type: "calculation", question: "Gebruik het verdunningsschema. 10,00 mL natuurazijn wordt verdund tot 100,0 mL. Van de verdunde oplossing verbruikt 25,00 mL 20,80 mL 0,1000 mol/L NaOH. Bereken de molariteit van CH₃COOH in de oorspronkelijke azijn.", correctAnswer: "0,8320 mol/L", modelAnswer: "1. Bereken mol NaOH:\nn = molariteit × volume\nn = 0,1000 mol/L × 0,02080 L = 0,002080 mol\n\n2. Reactieverhouding:\nCH₃COOH reageert 1 : 1 met NaOH.\nDus in 25,00 mL verdunde azijn zat 0,002080 mol CH₃COOH.\n\n3. Bereken molariteit verdunde azijn:\nmolariteit = mol / volume\nmolariteit = 0,002080 mol / 0,02500 L = 0,08320 mol/L\n\n4. Corrigeer voor verdunnen:\n10,00 mL is verdund tot 100,0 mL.\nVerdunningsfactor = 10.\n\n5. Oorspronkelijke azijn:\n0,08320 × 10 = 0,8320 mol/L.\n\nEindantwoord:\nDe molariteit van CH₃COOH in de oorspronkelijke azijn is 0,8320 mol/L.", steps: ["n(NaOH) = molariteit × volume", "1 : 1 met CH₃COOH", "molariteit verdunde azijn", "verdunningsfactor 10", "oorspronkelijke molariteit"], rubric: ["0,002080 mol NaOH", "1 : 1", "0,08320 mol/L verdund", "factor 10", "0,8320 mol/L"], visual: { type: "diagram", component: "QuestionTitrationDataFigure", variant: "dilution", alt: "Verdunningsschema van natuurazijn naar aliquot voor titratie", caption: "Gebruik de figuur om aliquot en verdunningsfactor uit elkaar te houden.", purpose: "calculation-support" } }),
  q({ id: "priority-m10-15", module: "M10", topic: "foutenanalyse", skill: "8+ redeneren", level: 4, type: "mixed", question: "Bij een azijntitratie vergeet een leerling de blanco-correctie van 0,18 mL af te trekken van een gemeten verbruik van 18,46 mL. Leg uit wat dit doet met de berekende molariteit van CH₃COOH en geef het gecorrigeerde volume.", modelAnswer: "Eindantwoord: de berekende molariteit wordt zonder correctie te hoog; het gecorrigeerde volume is 18,28 mL = 0,01828 L. De blanco 0,18 mL hoort niet bij neutralisatie van azijnzuur. Als je die niet aftrekt, schrijf je te veel NaOH toe aan CH₃COOH. Via n = molariteit × volume bereken je dan te veel mol NaOH en bij 1 : 1 te veel mol zuur.", rubric: ["te hoog", "18,28 mL", "0,01828 L", "blanco hoort niet bij zuur"], hints: ["Corrigeer het volume vóór je mol berekent.", "Vraag welke NaOH echt met zuur reageerde.", "Koppel het resultaat aan de 1 : 1-verhouding."] }),
  q({ id: "figure-m8-01", module: "M8", topic: "massaspectrum met figuur", skill: "figuur interpreteren", level: 2, type: "open", question: "Bepaal uit het oefenmassaspectrum welke piek de basispiek is en welke piek waarschijnlijk de M-piek is. Leg uit waarom die twee niet hetzelfde hoeven te zijn.", modelAnswer: "Eindantwoord: de piek met relatieve intensiteit 100% is de basispiek; de piek bij de hoogste relevante molecuulionmassa is waarschijnlijk de M-piek. In het spectrum is de hoogste piek niet automatisch het hele molecuulion. Een stabiel fragmention kan vaker ontstaan en daardoor de basispiek zijn. Chemisch klopt dit omdat ionisatie fragmentatie kan veroorzaken.", steps: ["Lees de y-as voor de hoogste piek.", "Lees de m/z-waarden.", "Koppel M aan het molecuulion.", "Leg fragmentatie uit."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "standard", alt: "Oefenmassaspectrum zonder antwoordlabels", caption: "Lees m/z en relatieve intensiteit; de labels geven het antwoord niet weg.", purpose: "interpret-spectrum" } }),
  q({ id: "figure-m8-02", module: "M8", topic: "M+2-patroon", skill: "isotopenpatroon verklaren", level: 3, type: "open", question: "Bepaal uit het oefenmassaspectrum of het M/M+2-patroon beter bij chloor of broom past. Welke conclusie mag je nog niet trekken?", modelAnswer: "Eindantwoord: het patroon past bij chloor als M en M+2 ongeveer 3 : 1 zijn; de volledige structuur is nog niet bewezen. In het spectrum liggen de pieken twee m/z-eenheden uit elkaar en de M+2-piek is veel kleiner dan M. Dat past bij ³⁵Cl/³⁷Cl. Het is een sterke aanwijzing voor één chlooratoom, maar fragmenten, IR of NMR zijn nodig voor een volledige structuur.", steps: ["Zoek M en M+2.", "Vergelijk de piekhoogten.", "Koppel 3 : 1 aan chloor.", "Beperk de conclusie."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "chlorine", alt: "Oefenmassaspectrum met M en M plus 2-patroon", caption: "Gebruik de verhouding van de pieken; de conclusie blijft een aanwijzing.", purpose: "interpret-spectrum" } }),
  q({ id: "figure-m8-03", module: "M8", topic: "fragmentatie", skill: "fragment en basispiek uitleggen", level: 3, type: "mixed", question: "Gebruik het oefenmassaspectrum. Leg uit waarom de basispiek een fragment kan zijn terwijl de M-piek bij hogere m/z ligt.", modelAnswer: "Eindantwoord: de basispiek is het meest intensieve ion, en dat kan een fragmention zijn. De M-piek hoort bij het hele molecuulion. Als het molecuulion makkelijk breekt en een bepaald fragment stabiel is, ontstaat dat fragment vaak. Daardoor kan het fragment de hoogste intensiteit hebben terwijl de M-piek bij hogere m/z ligt.", steps: ["Zoek de hoogste piek.", "Zoek de piek van het hele molecuulion.", "Leg uit wat fragmentatie is.", "Koppel stabiliteit aan intensiteit."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "standard", alt: "Oefenmassaspectrum met fragmenten en molecuulion", caption: "Hoogte en molecuulmassa zijn verschillende gegevens.", purpose: "interpret-spectrum" } }),
  q({ id: "figure-m8-04", module: "M8", topic: "M+2-patroon", skill: "isotopenpatroon verklaren", level: 2, type: "open", question: "Gebruik het oefenmassaspectrum. Past het M/M+2-patroon eerder bij chloor of broom? Onderbouw met de piekverhouding.", modelAnswer: "Eindantwoord: dit patroon past eerder bij broom als M en M+2 ongeveer even hoog zijn. Broom heeft twee veelvoorkomende isotopen, ⁷⁹Br en ⁸¹Br, die ongeveer 1 : 1 voorkomen en 2 u verschillen. Dat geeft een M+2-piek die ongeveer even groot is als M. De conclusie is een sterke aanwijzing voor Br, maar nog geen volledige structuur.", steps: ["Zoek M en M+2.", "Vergelijk de hoogtes.", "Koppel 1 : 1 aan broom.", "Noem het een aanwijzing."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "bromine", alt: "Oefenmassaspectrum met M en M plus 2 van vergelijkbare hoogte", caption: "Gebruik het piekpatroon om het halogeen te beredeneren.", purpose: "interpret-spectrum" } }),
  q({ id: "figure-m8-05", module: "M8", topic: "GC chromatogram", skill: "figuur interpreteren", level: 2, type: "open", question: "Gebruik het chromatogram. Hoeveel componenten zijn minimaal zichtbaar en welke as gebruik je voor de retentietijd?", modelAnswer: "Eindantwoord: er zijn minimaal drie zichtbare componenten. Elke afzonderlijke piek in een GC-chromatogram kan een component voorstellen. De horizontale as geeft de retentietijd in minuten. Dit is chemisch logisch omdat GC stoffen in de tijd scheidt voordat ze de detector bereiken.", steps: ["Tel de afzonderlijke pieken.", "Koppel elke piek aan een zichtbare component.", "Lees de x-as als retentietijd.", "Formuleer 'minimaal' als pieken overlappen kunnen."], visual: { type: "chromatogram", component: "QuestionGcChromatogram", variant: "three-peaks", alt: "Onlabeld GC-chromatogram met drie pieken", caption: "De oefenfiguur toont pieken zonder stofnamen.", purpose: "read-data" } }),
  q({ id: "priority-m8-01", module: "M8", topic: "massaspectrum", skill: "basispiek en M-piek", level: 2, type: "mixed", question: "Gebruik het oefenmassaspectrum. Welke piek is de basispiek, welke piek kan de M-piek zijn en waarom hoeven die niet samen te vallen?", modelAnswer: "Eindantwoord: de basispiek is de piek met 100% relatieve intensiteit; de M-piek is de piek van het molecuulion. Ze hoeven niet samen te vallen omdat een stabiel fragmention vaker kan ontstaan dan het hele molecuulion. In dat geval heeft het fragment de hoogste intensiteit, terwijl de M-piek nog steeds de massa van het hele geïoniseerde molecuul aanwijst.", steps: ["Lees de hoogste intensiteit.", "Zoek het molecuulion.", "Leg fragmentatie uit.", "Beperk de conclusie tot spectrumgegevens."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "standard", alt: "Oefenmassaspectrum met pieken voor basispiek en M-piek", caption: "Lees intensiteit en m/z apart.", purpose: "interpret-spectrum" } }),
  q({ id: "priority-m8-02", module: "M8", topic: "M+1", skill: "koolstof schatten", level: 3, type: "calculation", question: "Gebruik het oefenmassaspectrum. M+1 is 5,5% van M. Schat het aantal C-atomen met circa 1,1% ¹³C per C-atoom.", correctAnswer: "ongeveer 5 C-atomen", modelAnswer: "Eindantwoord: ongeveer 5 C-atomen. Gegeven: M+1 is 5,5% van M. Bij organische stoffen gebruik je als vuistregel ongeveer 1,1% M+1 per C-atoom door ¹³C. Berekening: 5,5 / 1,1 = 5. Chemisch klopt dit omdat elk C-atoom een kleine kans heeft om ¹³C te zijn. Het blijft een schatting, geen volledige structuuridentificatie.", steps: ["Lees de verhouding M+1/M.", "Deel door 1,1%.", "Noem het resultaat een schatting."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "carbon", alt: "Oefenmassaspectrum met M en M plus 1", caption: "Gebruik M+1 als koolstofaanwijzing, niet als volledige structuur.", purpose: "interpret-spectrum" } }),
  q({ id: "priority-m8-08", module: "M8", topic: "GC", skill: "retentietijd", level: 2, type: "open", question: "Gebruik het chromatogram. Stof bij de middelste piek komt later uit de kolom dan de eerste piek. Noem twee mogelijke verklaringen zonder alleen naar molmassa te wijzen.", modelAnswer: "Eindantwoord: de stof kan minder vluchtig zijn of sterker met de stationaire fase interageren. Uit het chromatogram lees je alleen dat de retentietijd groter is. Retentietijd hangt af van kolom, temperatuurprogramma, vluchtigheid en interacties met de stationaire fase, niet alleen van molmassa.", steps: ["Lees de retentietijden.", "Noem vluchtigheid.", "Noem interactie met stationaire fase.", "Beperk de conclusie."], visual: { type: "chromatogram", component: "QuestionGcChromatogram", variant: "three-peaks", alt: "Onlabeld GC-chromatogram met retentietijden", caption: "Gebruik retentietijd als gegeven; de figuur labelt de stoffen niet.", purpose: "read-data" } }),
  q({ id: "priority-m8-10", module: "M8", topic: "IR", skill: "functionele groep", level: 2, type: "open", question: "Een onbekende stof heeft in IR een sterke band die past bij C=O. Welke conclusie mag je trekken, en welke conclusie over de precieze stof mag je nog niet trekken?", modelAnswer: "Eindantwoord: een carbonylgroep is waarschijnlijk aanwezig; de precieze stof of exacte structuur is nog niet bewezen. Een C=O-band kan passen bij verschillende stofklassen, zoals aldehyde, keton, carbonzuur of ester. Chemisch klopt dit omdat IR vooral functionele groepen aanwijst. Voor volledige identificatie combineer je dit met MS, GC of NMR.", rubric: ["carbonylgroep waarschijnlijk", "geen exacte structuur", "combinatie met andere technieken"], hints: ["IR wijst vooral functionele groepen aan.", "Noem minstens twee mogelijke carbonylstofklassen.", "Beperk je conclusie."] }),
  q({ id: "priority-m8-14", module: "M8", topic: "massaspectrum", skill: "conclusies begrenzen", level: 4, type: "mixed", question: "Gebruik het oefenmassaspectrum. Het spectrum heeft M = 86, basispiek 43 en M+1 is 6,6% van M. Schrijf twee verdedigbare conclusies en één conclusie die nog niet mag.", modelAnswer: "Eindantwoord: verdedigbaar zijn een molecuulmassa rond 86 u en ongeveer zes C-atomen; niet verdedigbaar is de exacte volledige structuur of naam. De M-piek geeft het molecuulion rond m/z 86. De M+1-piek van 6,6% past met de vuistregel 1,1% per C bij ongeveer 6 C-atomen. m/z 43 kan een stabiel fragment zijn. Deze gegevens geven aanwijzingen, maar geen volledige structuur zonder extra IR/NMR of fragmentanalyse.", steps: ["Lees M.", "Gebruik M+1 / 1,1%.", "Benoem de basispiek als fragmentmogelijkheid.", "Begrens de conclusie."], visual: { type: "spectrum", component: "QuestionMassSpectrum", variant: "carbon", alt: "Oefenmassaspectrum met M, M plus 1 en fragmentpiek", caption: "Gebruik meerdere spectrumgegevens, maar trek geen volledige structuur uit één spectrum.", purpose: "interpret-spectrum" } }),
];
